import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function ViewApplications() {
  const [apps, setApps] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("applications")) || [];
    setApps(stored);
  }, []);

  return (
    <div style={{ marginTop: "25px" }}>
      <h2>Job Applications (Admin)</h2>

      <table className="designation-table">
        <thead>
          <tr>
            <th>S.No</th>
            <th>Employee</th>
            <th>Email</th>
            <th>Job Title</th>
            <th>Status</th>
            <th>Applied Date</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {apps.map((a, i) => (
            <tr key={a.id}>
              <td>{i + 1}</td>
              <td>{a.employeeName || a.employee}</td>
              <td>{a.email}</td>
              <td>{a.jobTitle}</td>
              <td>{a.status}</td>
              <td>{a.appliedDate || "--"}</td>

              <td>
                {a.status === "Approved" && (
                  <button
                    onClick={() =>
                      navigate(
                        `/dashboard/recruitment/offer-letter/${a.id}`
                      )
                    }
                  >
                    Create Offer
                  </button>
                )}

                {a.status === "Offer Sent" && (
                  <>
                    <button
                      onClick={() =>
                        navigate(
                          `/dashboard/recruitment/offer-letter/${a.id}`
                        )
                      }
                    >
                      Edit Offer
                    </button>

                    <button
                      onClick={() =>
                        navigate(
                          `/dashboard/recruitment/offer-preview/${a.id}`
                        )
                      }
                    >
                      View Offer
                    </button>
                  </>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ViewApplications;
